// bucket returns the bucket for key, creating it on first use.
func (l *Limiter) bucket(key string) *Bucket {
	l.mu.Lock()
	defer l.mu.Unlock()
	b, ok := l.buckets[key]
	if !ok {
		b = NewBucket(l.capacity, l.refillRate)
		b.now = l.now
		b.last = l.now()
		l.buckets[key] = b
	}
