}

// Allow reports whether the request may proceed, consuming a token if so.
func (l *Limiter) Allow(r *http.Request) bool {
	l.mu.Lock()
	keyFunc := l.keyFunc
	l.mu.Unlock()
	return l.bucket(keyFunc(r)).Allow()
}

// Remaining reports how many whole tokens are currently available for the
// request's key without consuming any.
func (l *Limiter) Remaining(r *http.Request) int {
	l.mu.Lock()
	keyFunc := l.keyFunc
	l.mu.Unlock()
