// retrying, derived from the refill rate. It is at least 1 when a positive rate
// is configured.
func (l *Limiter) retryAfterSeconds() int {
	if l.refillRate <= 0 {
		return 1
	}
	return int(math.Ceil(1 / l.refillRate))
}

// Middleware wraps next, responding with 429 Too Many Requests when the caller
// has exhausted its bucket. Every response carries X-RateLimit-Limit and
// X-RateLimit-Remaining headers, and 429 responses also carry Retry-After.
func (l *Limiter) Middleware(next http.Handler) http.Handler {
	return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		l.mu.Lock()
		keyFunc := l.keyFunc
		l.mu.Unlock()

		b := l.bucket(keyFunc(r))
		allowed := b.Allow()

		w.Header().Set("X-RateLimit-Limit", strconv.Itoa(l.capacity))
		w.Header().Set("X-RateLimit-Remaining", strconv.Itoa(int(math.Floor(b.Tokens()))))

		if !allowed {
			w.Header().Set("Retry-After", strconv.Itoa(l.retryAfterSeconds()))
			http.Error(w, "rate limit exceeded", http.StatusTooManyRequests)
			return
		}
		next.ServeHTTP(w, r)
	})
}
