package retry

import "time"

// Option configures the behaviour of Retry and Do.
type Option func(*config)

// config holds the resolved settings for a single Retry/Do invocation.
type config struct {
	maxDelay time.Duration // upper bound on each backoff delay; 0 means unbounded
}

// WithMaxDelay caps the exponential backoff so no individual wait exceeds d. The
// delay still doubles up to the cap. A non-positive d leaves the delay
// unbounded.
func WithMaxDelay(d time.Duration) Option {
	return func(c *config) {
		if d > 0 {
			c.maxDelay = d
		}
	}
}

// newConfig applies opts on top of the zero-value defaults.
func newConfig(opts []Option) config {
	var c config
	for _, opt := range opts {
		opt(&c)
	}
	return c
}

// clamp returns d limited to the configured maximum delay, if one is set.
func (c config) clamp(d time.Duration) time.Duration {
	if c.maxDelay > 0 && d > c.maxDelay {
		return c.maxDelay
	}
	return d
}
