package pq

import "testing"

func TestPushPopOrder(t *testing.T) {
	tests := []struct {
		name  string
		input []struct {
			item     string
			priority int
		}
		want []string
	}{
		{
			name: "ascending priorities",
			input: []struct {
				item     string
				priority int
			}{
				{"a", 1}, {"b", 2}, {"c", 3},
			},
			want: []string{"a", "b", "c"},
		},
		{
			name: "out of order insert",
			input: []struct {
				item     string
				priority int
			}{
				{"c", 3}, {"a", 1}, {"b", 2},
			},
			want: []string{"a", "b", "c"},
		},
		{
			name: "negative priorities",
			input: []struct {
				item     string
				priority int
			}{
				{"low", -5}, {"mid", 0}, {"high", 10},
			},
			want: []string{"low", "mid", "high"},
		},
		{
			name: "single element",
			input: []struct {
				item     string
				priority int
			}{
				{"only", 42},
			},
			want: []string{"only"},
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			q := New[string]()
			for _, in := range tt.input {
				q.Push(in.item, in.priority)
			}
			if got := q.Len(); got != len(tt.want) {
				t.Fatalf("Len() = %d, want %d", got, len(tt.want))
			}
			var got []string
			for q.Len() > 0 {
				v, ok := q.Pop()
				if !ok {
					t.Fatalf("Pop() returned ok=false with Len()=%d", q.Len())
				}
				got = append(got, v)
			}
			if len(got) != len(tt.want) {
				t.Fatalf("popped %d items, want %d", len(got), len(tt.want))
			}
			for i := range tt.want {
				if got[i] != tt.want[i] {
					t.Errorf("position %d = %q, want %q", i, got[i], tt.want[i])
				}
			}
		})
	}
}

func TestPopEmpty(t *testing.T) {
	q := New[int]()
	v, ok := q.Pop()
	if ok {
		t.Fatalf("Pop() on empty queue returned ok=true, value=%d", v)
	}
	if v != 0 {
		t.Errorf("Pop() on empty queue returned value=%d, want zero value 0", v)
	}
	if q.Len() != 0 {
		t.Errorf("Len() = %d on empty queue, want 0", q.Len())
	}
}

