		t.Fatalf("Fire(eventStart): unexpected error: %v", err)
	}
	if err := m.Fire(eventPause); err != nil {
		t.Fatalf("Fire(eventPause): unexpected error: %v", err)
	}

	want := []record{
		{stateIdle, eventStart, stateRunning},
		{stateRunning, eventPause, statePaused},
	}
	if len(got) != len(want) {
		t.Fatalf("observer called %d times, want %d (%+v)", len(got), len(want), got)
	}
	for i := range want {
		if got[i] != want[i] {
			t.Errorf("call %d = %+v, want %+v", i, got[i], want[i])
		}
	}
