	calls := 0
	m := newTrafficMachine()
	m.OnTransition(func(from state, e event, to state) { calls++ })

	if err := m.Fire(eventPause); !errors.Is(err, ErrInvalidTransition) { // illegal from idle
		t.Fatalf("Fire(eventPause): err = %v, want ErrInvalidTransition", err)
	}
	if calls != 0 {
		t.Errorf("observer called %d times on rejected event, want 0", calls)
	}
}

func TestOnTransitionMultipleObserversInOrder(t *testing.T) {
	var order []int
	m := New[state, event](stateIdle)
	m.Permit(stateIdle, eventStart, stateRunning)
	m.OnTransition(func(_ state, _ event, _ state) { order = append(order, 1) })
	m.OnTransition(func(_ state, _ event, _ state) { order = append(order, 2) })
	m.OnTransition(nil) // nil observers are ignored, not stored

