```go
package pool

// Option configures a Pool at construction time. Options are passed to New.
type Option[T any] func(*Pool[T])

// WithMaxIdle bounds the number of idle values the pool retains. Once the
// pool holds n idle values, further Put calls discard their value instead
// of growing the pool, capping memory use. A value of n <= 0 means the
// pool is unbounded (the default).
func WithMaxIdle[T any](n int) Option[T] {
	return func(p *Pool[T]) {
		if n < 0 {
			n = 0
		}
		p.maxIdle = n
	}
}
