// Package pagerepo provides a concurrency-safe, in-memory repository of
// records with filtered, sorted, and paginated querying.
package pagerepo

import (
	"sort"
	"sync"
)

// Repository is a concurrency-safe, in-memory collection of records of type R.
// The zero value is not ready for use; call New.
type Repository[R any] struct {
	mu    sync.RWMutex
	items []R
}

// New returns an empty Repository ready for use.
func New[R any]() *Repository[R] {
	return &Repository[R]{}
}

// Add appends a record to the repository. It is safe for concurrent use.
func (r *Repository[R]) Add(item R) {
	r.mu.Lock()
	defer r.mu.Unlock()
	r.items = append(r.items, item)
}

// Len reports the number of records currently stored.
func (r *Repository[R]) Len() int {
	r.mu.RLock()
	defer r.mu.RUnlock()
	return len(r.items)
}

// Page is a single page of query results together with the pagination
// metadata describing the full filtered result set. It lets callers render
// pager controls such as "showing items 11-20 of 57".
type Page[R any] struct {
	Items      []R // the records on this page
	Page       int // the requested 1-based page number
	Size       int // the requested page size
	Total      int // total number of records matching the filter
	TotalPages int // number of pages of Size needed to hold Total records
}

// Query returns a single page of records.
//
// The records are first filtered with filter (a nil filter keeps every
// record), then ordered with sortLess (a nil sortLess preserves insertion
// order), and finally the page-th page of the given size is returned.
//
// Pages are 1-based: page 1 is the first page. A page or size that is out of
// range, or a page that lies beyond the available data, yields a non-nil,
// empty slice. The returned slice is a fresh copy and never aliases the
// repository's internal storage.
func (r *Repository[R]) Query(filter func(R) bool, sortLess func(a, b R) bool, page, size int) []R {
	return pageSlice(r.matchedSorted(filter, sortLess), page, size)
}

// QueryPage behaves exactly like Query for selecting Items, but additionally
// reports pagination metadata (Total and TotalPages) describing the full
// filtered result set. Total is reported even when page or size is out of
// range; TotalPages is zero when size is less than 1.
func (r *Repository[R]) QueryPage(filter func(R) bool, sortLess func(a, b R) bool, page, size int) Page[R] {
	matched := r.matchedSorted(filter, sortLess)
	total := len(matched)
	totalPages := 0
	if size >= 1 {
		totalPages = (total + size - 1) / size
	}
	return Page[R]{
		Items:      pageSlice(matched, page, size),
		Page:       page,
		Size:       size,
		Total:      total,
		TotalPages: totalPages,
	}
}

// matchedSorted returns a fresh slice of every record passing filter, ordered
// by sortLess. A nil filter keeps every record; a nil sortLess preserves
// insertion order.
func (r *Repository[R]) matchedSorted(filter func(R) bool, sortLess func(a, b R) bool) []R {
	r.mu.RLock()
	matched := make([]R, 0, len(r.items))
	for _, item := range r.items {
		if filter == nil || filter(item) {
			matched = append(matched, item)
		}
	}
	r.mu.RUnlock()

	if sortLess != nil {
		sort.SliceStable(matched, func(i, j int) bool {
			return sortLess(matched[i], matched[j])
		})
	}
	return matched
}

// pageSlice returns a fresh copy of the page-th page (1-based) of the given
// size from items. An out-of-range page or size, or a page beyond the data,
// yields a non-nil, empty slice.
func pageSlice[R any](items []R, page, size int) []R {
	if page < 1 || size < 1 {
		return []R{}
	}
	start := (page - 1) * size
	if start >= len(items) {
		return []R{}
	}
	end := start + size
	if end > len(items) {
		end = len(items)
	}
	out := make([]R, end-start)
	copy(out, items[start:end])
	return out
}
